mapper.select:
SELECT DISTINCT s.sId AS sid, s.sNo AS sno, s.sName AS sname, s.sSex AS ssex, s.sClassId AS sclassid, c.cName AS className, cr.crId AS courseid, cr.crName AS courseName, yt.yId AS termid, CONCAT(yt.yYear, '-', yt.yTerm) AS termName FROM teaching tc INNER JOIN studentinfo s ON tc.tcClassId = s.sClassId LEFT JOIN classinfo c ON s.sClassId = c.cId LEFT JOIN courseinfo cr ON tc.tcCourseId = cr.crId LEFT JOIN yearterm yt ON tc.tcTermId = yt.yId WHERE tc.tcTeacherId = #{teacherId}
AND tc.tcTermId = #{dto.tctermid}
AND tc.tcCourseId = #{dto.tccourseid}
AND tc.tcClassId = #{dto.tcclassid}
AND ( s.sNo LIKE CONCAT('%', #{dto.qkey}, '%') OR s.sName LIKE CONCAT('%', #{dto.qkey}, '%') )
ORDER BY s.sId DESC
